mapper.select:
select
	v.activityalias_                 ,
	v.businessstate_                 ,
	t1.id                             ,
	t1.secret_level                   ,
	t1.project_id                     ,
	t1.project_name                   ,
	t1.task_id                        ,
	t1.task_name                      ,
	t1.zyjk_ys_date                   ,
	t1.zyjk_name                      ,
	t1.zyjk_date                      ,
	t1.zyjk_no                        ,
	t1.hb_ys_date                     ,
	t1.hb_name                        ,
	t1.hb_date                        ,
	t1.hb_no                          ,
	t1.aq_ys_date                     ,
	t1.aq_name                        ,
	t1.aq_date                        ,
	t1.aq_no                          ,
	t1.created_by                     ,
	t1.creation_date                  ,
	t1.last_updated_by                ,
	t1.last_update_date               ,
	t1.last_update_ip                 ,
	t1.version                        ,
	t1.created_dept                   ,
	t1.org_identity                   ,
	t1.attribute_01                   ,
	t1.attribute_02                   ,
	t1.attribute_03                   ,
	t1.attribute_04                   ,
	t1.attribute_05                   ,
	t1.attribute_06                   ,
	t1.attribute_07                   ,
	t1.attribute_08                   ,
	t1.attribute_09                   ,
	t1.attribute_10                   
from pm_project_ys_sts 	t1 left join bpm_client_hist_procinst_v v on t1.id = v.formid_ 


			and t1.ID =#{id}


			and t1.SECRET_LEVEL =#{secretLevel}


			and t1.PROJECT_ID =#{projectId}


			and t1.PROJECT_NAME =#{projectName}


			and t1.TASK_ID =#{taskId}


			and t1.TASK_NAME =#{taskName}


			and t1.ZYJK_YS_DATE =#{zyjkYsDate}


			and t1.ZYJK_NAME =#{zyjkName}


			and t1.ZYJK_DATE >= #{zyjkDateBegin}


			and t1.ZYJK_DATE <= #{zyjkDateEnd}


			and t1.ZYJK_NO =#{zyjkNo}


			and t1.HB_YS_DATE =#{hbYsDate}


			and t1.HB_NAME =#{hbName}


			and t1.HB_DATE >= #{hbDateBegin}


			and t1.HB_DATE <= #{hbDateEnd}


			and t1.HB_NO =#{hbNo}


			and t1.AQ_YS_DATE =#{aqYsDate}


			and t1.AQ_NAME =#{aqName}


			and t1.AQ_DATE >= #{aqDateBegin}


			and t1.AQ_DATE <= #{aqDateEnd}


			and t1.AQ_NO =#{aqNo}


			and t1.CREATED_BY =#{createdBy}


			and t1.CREATION_DATE =#{creationDate}


			and t1.LAST_UPDATED_BY =#{lastUpdatedBy}


			and t1.LAST_UPDATE_DATE =#{lastUpdateDate}


			and t1.LAST_UPDATE_IP =#{lastUpdateIp}


			and t1.VERSION =#{version}


			and t1.CREATED_DEPT =#{createdDept}


			and t1.ORG_IDENTITY =#{orgIdentity}


			and t1.ATTRIBUTE_01 =#{attribute01}


			and t1.ATTRIBUTE_02 =#{attribute02}


			and t1.ATTRIBUTE_03 =#{attribute03}


			and t1.ATTRIBUTE_04 =#{attribute04}


			and t1.ATTRIBUTE_05 =#{attribute05}


			and t1.ATTRIBUTE_06 =#{attribute06}


			and t1.ATTRIBUTE_07 =#{attribute07}


			and t1.ATTRIBUTE_08 =#{attribute08}


			and t1.ATTRIBUTE_09 =#{attribute09}


			and t1.ATTRIBUTE_10 =#{attribute10}


			 and exists (select 1 from BPM_CLIENT_HIST_TASK_V os where os.task_b_id_ = t1.id and os.assignee_ = #{currUserId}) 


			and v.businessstate_ = #{bpmState}
